import numpy as np

def assign_node(node_id, unassigned_nodes, adjacency_matrix, current_partition):
    total_nodes = len(current_partition)
    # 计算当前总跨边权重（只考虑已分配节点间的边）
    current_cross = 0.0
    for i in range(total_nodes):
        if current_partition[i] != -1:
            for j in range(i+1, total_nodes):
                if current_partition[j] != -1 and current_partition[i] != current_partition[j]:
                    current_cross += adjacency_matrix[i, j]

    # 模拟分配到0侧时的新划分
    new_partition_0 = current_partition.copy()
    new_partition_0[node_id] = 0
    cross_0 = current_cross
    for j in range(total_nodes):
        if node_id != j:
            if new_partition_0[j] != -1 and new_partition_0[node_id] != new_partition_0[j]:
                cross_0 += adjacency_matrix[node_id, j]

    # 模拟分配到1侧时的新划分
    new_partition_1 = current_partition.copy()
    new_partition_1[node_id] = 1
    cross_1 = current_cross
    for j in range(total_nodes):
        if node_id != j:
            if new_partition_1[j] != -1 and new_partition_1[node_id] != new_partition_1[j]:
                cross_1 += adjacency_matrix[node_id, j]

    # 选择使总跨边更大的侧，相等则默认0
    if cross_0 >= cross_1:
        return 0
    else:
        return 1

import numpy as np

def assign_node(node_id, unassigned_nodes, adjacency_matrix, current_partition):
    # 计算分配到0侧时，与已分配1侧节点之间的边权之和
    gain0 = 0
    # 计算分配到1侧时，与已分配0侧节点之间的边权之和
    gain1 = 0
    for neighbor in range(len(current_partition)):
        if not unassigned_nodes[neighbor] and current_partition[neighbor] != -1:
            if current_partition[neighbor] == 1:
                gain0 += adjacency_matrix[node_id, neighbor]
            else:  # current_partition[neighbor] == 0
                gain1 += adjacency_matrix[node_id, neighbor]
    # 选择增益更大的侧，若相等则默认0
    if gain0 >= gain1:
        return 0
    else:
        return 1
